import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchReservations, cancelReservation } from '../features/reservations/reservationsSlice';

const STATUS_COLORS = {
  confirmed: '#2ecc71', pending: '#f39c12', seated: '#3498db',
  completed: '#95a5a6', cancelled: '#e74c3c', 'no-show': '#c0392b',
};

export default function MyReservationsPage() {
  const dispatch = useDispatch();
  const { data, total, pages, loading } = useSelector(s => s.reservations);
  const [filters, setFilters] = useState({ status: '', date: '', page: 1 });

  useEffect(() => { dispatch(fetchReservations({ ...filters, limit: 10 })); }, [filters]);

  const handleCancel = async (id) => {
    if (window.confirm('Cancel this reservation?')) dispatch(cancelReservation(id));
  };

  return (
    <div style={styles.wrap}>
      <h2>My Reservations</h2>
      <div style={styles.filters}>
        <input style={styles.input} type="date" value={filters.date}
          onChange={e => setFilters({ ...filters, date: e.target.value, page: 1 })} />
        <select style={styles.input} value={filters.status}
          onChange={e => setFilters({ ...filters, status: e.target.value, page: 1 })}>
          <option value="">All Statuses</option>
          {['pending','confirmed','seated','completed','cancelled','no-show'].map(s =>
            <option key={s} value={s}>{s}</option>)}
        </select>
      </div>

      {loading ? <p>Loading...</p> : (
        <>
          <p style={{ color: '#666' }}>{total} reservation(s)</p>
          {data.map(r => (
            <div key={r.id} style={styles.card}>
              <div style={styles.row}>
                <span><strong>Table {r.table?.number || r.tableId}</strong> — {r.date} at {r.time}</span>
                <span style={{ ...styles.badge, background: STATUS_COLORS[r.status] }}>{r.status}</span>
              </div>
              <p style={{ margin: '4px 0', color: '#555' }}>Guests: {r.guests} {r.notes && `| Notes: ${r.notes}`}</p>
              {['confirmed', 'pending'].includes(r.status) && (
                <button style={styles.cancelBtn} onClick={() => handleCancel(r.id)}>Cancel</button>
              )}
            </div>
          ))}
          <div style={styles.pagination}>
            {Array.from({ length: pages }, (_, i) => (
              <button key={i} style={{ ...styles.pageBtn, fontWeight: filters.page === i+1 ? 'bold' : 'normal' }}
                onClick={() => setFilters({ ...filters, page: i+1 })}>{i+1}</button>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

const styles = {
  wrap:       { maxWidth: 800, margin: '32px auto', padding: '0 16px' },
  filters:    { display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap' },
  input:      { padding: '8px', border: '1px solid #ddd', borderRadius: 4, fontSize: '0.95rem' },
  card:       { background: '#fff', padding: 16, borderRadius: 8, marginBottom: 12, boxShadow: '0 1px 6px rgba(0,0,0,0.08)' },
  row:        { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  badge:      { color: '#fff', padding: '3px 10px', borderRadius: 12, fontSize: '0.8rem' },
  cancelBtn:  { marginTop: 8, padding: '6px 14px', background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
  pagination: { display: 'flex', gap: 8, marginTop: 16 },
  pageBtn:    { padding: '6px 12px', border: '1px solid #ddd', borderRadius: 4, cursor: 'pointer', background: '#fff' },
};
